//! Extension trait implementation for provisioning.

use std::sync::Arc;

use convergio_db::pool::ConnPool;
use convergio_types::extension::{AppContext, Extension, Health, McpToolDef, Metric, Migration};
use convergio_types::manifest::{Capability, Manifest, ModuleKind};

use crate::routes::{provision_routes, ProvisionState};

pub struct ProvisioningExtension {
    pool: ConnPool,
}

impl ProvisioningExtension {
    pub fn new(pool: ConnPool) -> Self {
        Self { pool }
    }
}

impl Extension for ProvisioningExtension {
    fn manifest(&self) -> Manifest {
        Manifest {
            id: "convergio-provisioning".to_string(),
            description: "Node provisioning — sync config, keys, binary to remote peers"
                .to_string(),
            version: env!("CARGO_PKG_VERSION").to_string(),
            kind: ModuleKind::Extension,
            provides: vec![Capability {
                name: "node-provisioning".to_string(),
                version: "1.0.0".to_string(),
                description: "Sync config/keys/binary to peers via rsync/SSH".to_string(),
            }],
            requires: vec![],
            agent_tools: vec![],
            required_roles: vec!["orchestrator".into(), "all".into()],
        }
    }

    fn routes(&self, _ctx: &AppContext) -> Option<axum::Router> {
        let state = Arc::new(ProvisionState {
            pool: self.pool.clone(),
        });
        Some(provision_routes(state))
    }

    fn migrations(&self) -> Vec<Migration> {
        vec![Migration {
            version: 1,
            description: "provisioning tables",
            up: "CREATE TABLE IF NOT EXISTS provision_runs (\
                    id INTEGER PRIMARY KEY,\
                    peer_name TEXT NOT NULL,\
                    ssh_target TEXT NOT NULL,\
                    status TEXT DEFAULT 'pending',\
                    items_total INTEGER DEFAULT 0,\
                    items_done INTEGER DEFAULT 0,\
                    started_at TEXT DEFAULT (datetime('now')),\
                    completed_at TEXT,\
                    error_message TEXT\
                );\
                CREATE INDEX IF NOT EXISTS idx_pr_peer \
                    ON provision_runs(peer_name);\
                CREATE INDEX IF NOT EXISTS idx_pr_status \
                    ON provision_runs(status);\
                CREATE TABLE IF NOT EXISTS provision_items (\
                    id INTEGER PRIMARY KEY,\
                    run_id INTEGER NOT NULL REFERENCES provision_runs(id),\
                    item_type TEXT NOT NULL,\
                    source_path TEXT,\
                    dest_path TEXT,\
                    status TEXT DEFAULT 'pending',\
                    bytes_transferred INTEGER DEFAULT 0,\
                    duration_ms INTEGER DEFAULT 0,\
                    error_message TEXT\
                );\
                CREATE INDEX IF NOT EXISTS idx_pi_run \
                    ON provision_items(run_id);",
        }]
    }

    fn health(&self) -> Health {
        match self.pool.get() {
            Ok(_) => Health::Ok,
            Err(e) => Health::Degraded {
                reason: format!("db: {e}"),
            },
        }
    }

    fn metrics(&self) -> Vec<Metric> {
        let run_count: f64 = self
            .pool
            .get()
            .ok()
            .and_then(|c| {
                c.query_row("SELECT COUNT(*) FROM provision_runs", [], |r| {
                    r.get::<_, i64>(0)
                })
                .ok()
            })
            .unwrap_or(0) as f64;
        vec![Metric {
            name: "provision_runs_total".to_string(),
            value: run_count,
            labels: vec![],
        }]
    }

    fn mcp_tools(&self) -> Vec<McpToolDef> {
        crate::mcp_defs::provisioning_tools()
    }
}

//! convergio-provisioning — sync config/keys/binary to remote nodes.
//!
//! Orchestrates rsync operations to provision peer nodes with:
//! - Config files (~/.convergio/config.toml, env)
//! - Agent definitions (claude-config/ TOML files)
//! - Daemon binary (target/release/convergio)
//! - Memory/context data
//!
//! DB tables: provision_runs, provision_items.

pub mod ext;
pub mod provision;
pub mod routes;
pub mod types;

pub use ext::ProvisioningExtension;
pub use types::{ProvisionItem, ProvisionRun, ProvisionStatus};

pub mod mcp_defs;
#[cfg(test)]
mod tests;

//! MCP tool definitions for the provisioning extension.

use convergio_types::extension::McpToolDef;
use serde_json::json;

pub fn provisioning_tools() -> Vec<McpToolDef> {
    vec![
        McpToolDef {
            name: "cvg_provision_peer".into(),
            description: "Provision a new mesh peer.".into(),
            method: "POST".into(),
            path: "/api/provision/peer".into(),
            input_schema: json!({
                "type": "object",
                "properties": {
                    "hostname": {"type": "string"},
                    "ssh_user": {"type": "string"}
                },
                "required": ["hostname"]
            }),
            min_ring: "core".into(),
            path_params: vec![],
        },
        McpToolDef {
            name: "cvg_provision_runs".into(),
            description: "List provisioning runs.".into(),
            method: "GET".into(),
            path: "/api/provision/runs".into(),
            input_schema: json!({"type": "object", "properties": {}}),
            min_ring: "community".into(),
            path_params: vec![],
        },
        McpToolDef {
            name: "cvg_provision_run".into(),
            description: "Get details of a provisioning run.".into(),
            method: "GET".into(),
            path: "/api/provision/run/:id".into(),
            input_schema: json!({
                "type": "object",
                "properties": {"id": {"type": "string"}},
                "required": ["id"]
            }),
            min_ring: "community".into(),
            path_params: vec!["id".into()],
        },
    ]
}

//! Core provisioning logic — orchestrates rsync operations to remote peers.

use crate::types::{ProvisionItemType, ProvisionRequest, ProvisionStatus};
use convergio_db::pool::ConnPool;
use std::time::Instant;

/// Execute a full provisioning run for a peer.
pub async fn provision_peer(pool: &ConnPool, req: &ProvisionRequest) -> Result<i64, String> {
    let run_id = create_run(pool, &req.peer_name, &req.ssh_target)?;
    update_run_status(pool, run_id, ProvisionStatus::Running);

    let mut items_done = 0u32;
    let mut items_total = 0u32;
    let mut last_error: Option<String> = None;

    // Config files
    if req.include_config {
        items_total += 1;
        let source = convergio_types::platform_paths::convergio_data_dir();
        match rsync_item(
            pool,
            run_id,
            ProvisionItemType::Config,
            &source.to_string_lossy(),
            &req.remote_base,
            &req.ssh_target,
            &["*.db", "*.db-wal", "*.db-shm"],
        )
        .await
        {
            Ok(_) => items_done += 1,
            Err(e) => last_error = Some(e),
        }
    }

    // Agent definitions
    if req.include_agent_defs {
        items_total += 1;
        let repo_root = std::env::var("CONVERGIO_REPO_ROOT")
            .or_else(|_| std::env::current_dir().map(|p| p.display().to_string()))
            .unwrap_or_else(|_| ".".into());
        let source = format!("{repo_root}/claude-config/");
        let dest = format!("{}/agent-defs/", req.remote_base);
        match rsync_item(
            pool,
            run_id,
            ProvisionItemType::AgentDefs,
            &source,
            &dest,
            &req.ssh_target,
            &[],
        )
        .await
        {
            Ok(_) => items_done += 1,
            Err(e) => last_error = Some(e),
        }
    }

    // Binary
    if req.include_binary {
        items_total += 1;
        let repo_root = std::env::var("CONVERGIO_REPO_ROOT")
            .or_else(|_| std::env::current_dir().map(|p| p.display().to_string()))
            .unwrap_or_else(|_| ".".into());
        let source = format!("{repo_root}/daemon/target/release/convergio");
        let dest = format!("{}/bin/convergio", req.remote_base);
        match rsync_item(
            pool,
            run_id,
            ProvisionItemType::Binary,
            &source,
            &dest,
            &req.ssh_target,
            &[],
        )
        .await
        {
            Ok(_) => items_done += 1,
            Err(e) => last_error = Some(e),
        }
    }

    // Memory/context
    if req.include_memory {
        items_total += 1;
        let source = convergio_types::platform_paths::convergio_data_dir().join("memory");
        let dest = format!("{}/memory/", req.remote_base);
        match rsync_item(
            pool,
            run_id,
            ProvisionItemType::Memory,
            &source.to_string_lossy(),
            &dest,
            &req.ssh_target,
            &[],
        )
        .await
        {
            Ok(_) => items_done += 1,
            Err(e) => last_error = Some(e),
        }
    }

    let status = if items_done == items_total {
        ProvisionStatus::Success
    } else {
        ProvisionStatus::Failed
    };
    complete_run(pool, run_id, status, items_total, items_done, last_error);
    Ok(run_id)
}

async fn rsync_item(
    pool: &ConnPool,
    run_id: i64,
    item_type: ProvisionItemType,
    source: &str,
    dest: &str,
    ssh_target: &str,
    exclude: &[&str],
) -> Result<(), String> {
    let item_id = create_item(pool, run_id, item_type, source, dest)?;
    update_item_status(pool, item_id, ProvisionStatus::Running);

    let start = Instant::now();
    let mut cmd = tokio::process::Command::new("rsync");
    cmd.args([
        "-avz",
        "-e",
        "ssh -o BatchMode=yes -o StrictHostKeyChecking=accept-new -o ConnectTimeout=10",
    ]);
    for pat in exclude {
        cmd.arg(format!("--exclude={pat}"));
    }
    cmd.arg(source);
    cmd.arg(format!("{ssh_target}:{dest}"));

    let output = cmd
        .output()
        .await
        .map_err(|e: std::io::Error| e.to_string())?;
    let duration_ms = start.elapsed().as_millis() as u64;

    if output.status.success() {
        complete_item(
            pool,
            item_id,
            ProvisionStatus::Success,
            0,
            duration_ms,
            None,
        );
        Ok(())
    } else {
        let err = String::from_utf8_lossy(&output.stderr).to_string();
        complete_item(
            pool,
            item_id,
            ProvisionStatus::Failed,
            0,
            duration_ms,
            Some(&err),
        );
        Err(err)
    }
}

// --- DB helpers ---

fn create_run(pool: &ConnPool, peer: &str, ssh: &str) -> Result<i64, String> {
    let conn = pool.get().map_err(|e| e.to_string())?;
    conn.execute(
        "INSERT INTO provision_runs (peer_name, ssh_target, status) VALUES (?1, ?2, 'pending')",
        rusqlite::params![peer, ssh],
    )
    .map_err(|e| e.to_string())?;
    Ok(conn.last_insert_rowid())
}

fn update_run_status(pool: &ConnPool, id: i64, status: ProvisionStatus) {
    if let Ok(conn) = pool.get() {
        let _ = conn.execute(
            "UPDATE provision_runs SET status = ?1 WHERE id = ?2",
            rusqlite::params![status.to_string(), id],
        );
    }
}

fn complete_run(
    pool: &ConnPool,
    id: i64,
    status: ProvisionStatus,
    total: u32,
    done: u32,
    error: Option<String>,
) {
    if let Ok(conn) = pool.get() {
        let _ = conn.execute(
            "UPDATE provision_runs SET status=?1, items_total=?2, items_done=?3, \
             error_message=?4, completed_at=datetime('now') WHERE id=?5",
            rusqlite::params![status.to_string(), total, done, error, id],
        );
    }
}

fn create_item(
    pool: &ConnPool,
    run_id: i64,
    item_type: ProvisionItemType,
    source: &str,
    dest: &str,
) -> Result<i64, String> {
    let conn = pool.get().map_err(|e| e.to_string())?;
    conn.execute(
        "INSERT INTO provision_items (run_id, item_type, source_path, dest_path, status) \
         VALUES (?1, ?2, ?3, ?4, 'pending')",
        rusqlite::params![run_id, item_type.to_string(), source, dest],
    )
    .map_err(|e| e.to_string())?;
    Ok(conn.last_insert_rowid())
}

fn update_item_status(pool: &ConnPool, id: i64, status: ProvisionStatus) {
    if let Ok(conn) = pool.get() {
        let _ = conn.execute(
            "UPDATE provision_items SET status = ?1 WHERE id = ?2",
            rusqlite::params![status.to_string(), id],
        );
    }
}

fn complete_item(
    pool: &ConnPool,
    id: i64,
    status: ProvisionStatus,
    bytes: u64,
    duration_ms: u64,
    error: Option<&str>,
) {
    if let Ok(conn) = pool.get() {
        let _ = conn.execute(
            "UPDATE provision_items SET status=?1, bytes_transferred=?2, \
             duration_ms=?3, error_message=?4 WHERE id=?5",
            rusqlite::params![status.to_string(), bytes, duration_ms, error, id],
        );
    }
}

//! HTTP routes for node provisioning.
//!
//! - POST /api/provision/peer     — trigger provisioning for a peer
//! - GET  /api/provision/runs     — list provisioning runs
//! - GET  /api/provision/run/:id  — get a specific run with items

use std::sync::Arc;

use axum::extract::{Path, Query, State};
use axum::response::Json;
use axum::routing::{get, post};
use axum::Router;
use convergio_db::pool::ConnPool;
use serde::Deserialize;
use serde_json::{json, Value};

use crate::provision::provision_peer;
use crate::types::ProvisionRequest;

pub struct ProvisionState {
    pub pool: ConnPool,
}

pub fn provision_routes(state: Arc<ProvisionState>) -> Router {
    Router::new()
        .route("/api/provision/peer", post(handle_provision))
        .route("/api/provision/runs", get(handle_list_runs))
        .route("/api/provision/run/{id}", get(handle_get_run))
        .with_state(state)
}

async fn handle_provision(
    State(s): State<Arc<ProvisionState>>,
    Json(req): Json<ProvisionRequest>,
) -> Json<Value> {
    let pool = s.pool.clone();
    let peer = req.peer_name.clone();
    tokio::spawn(async move {
        match provision_peer(&pool, &req).await {
            Ok(run_id) => tracing::info!(run_id, peer = %peer, "provisioning complete"),
            Err(e) => tracing::warn!(peer = %peer, error = %e, "provisioning failed"),
        }
    });
    Json(json!({"ok": true, "message": "provisioning started"}))
}

#[derive(Deserialize, Default)]
struct ListQuery {
    limit: Option<u32>,
}

async fn handle_list_runs(
    State(s): State<Arc<ProvisionState>>,
    Query(q): Query<ListQuery>,
) -> Json<Value> {
    let conn = match s.pool.get() {
        Ok(c) => c,
        Err(e) => return Json(json!({"error": e.to_string()})),
    };
    let limit = q.limit.unwrap_or(20).min(100);
    let sql = format!(
        "SELECT id, peer_name, ssh_target, status, items_total, items_done, \
         started_at, completed_at, error_message \
         FROM provision_runs ORDER BY id DESC LIMIT {limit}"
    );
    let mut stmt = match conn.prepare(&sql) {
        Ok(s) => s,
        Err(e) => return Json(json!({"error": e.to_string()})),
    };
    let rows: Vec<Value> = stmt
        .query_map([], |r| {
            Ok(json!({
                "id": r.get::<_, i64>(0)?,
                "peer_name": r.get::<_, String>(1)?,
                "ssh_target": r.get::<_, String>(2)?,
                "status": r.get::<_, String>(3)?,
                "items_total": r.get::<_, u32>(4)?,
                "items_done": r.get::<_, u32>(5)?,
                "started_at": r.get::<_, String>(6)?,
                "completed_at": r.get::<_, Option<String>>(7)?,
                "error": r.get::<_, Option<String>>(8)?,
            }))
        })
        .map(|rows| rows.flatten().collect())
        .unwrap_or_default();
    Json(json!({"runs": rows}))
}

async fn handle_get_run(State(s): State<Arc<ProvisionState>>, Path(id): Path<i64>) -> Json<Value> {
    let conn = match s.pool.get() {
        Ok(c) => c,
        Err(e) => return Json(json!({"error": e.to_string()})),
    };
    let run = conn.query_row(
        "SELECT id, peer_name, ssh_target, status, items_total, items_done, \
         started_at, completed_at, error_message FROM provision_runs WHERE id = ?1",
        [id],
        |r| {
            Ok(json!({
                "id": r.get::<_, i64>(0)?,
                "peer_name": r.get::<_, String>(1)?,
                "ssh_target": r.get::<_, String>(2)?,
                "status": r.get::<_, String>(3)?,
                "items_total": r.get::<_, u32>(4)?,
                "items_done": r.get::<_, u32>(5)?,
                "started_at": r.get::<_, String>(6)?,
                "completed_at": r.get::<_, Option<String>>(7)?,
                "error": r.get::<_, Option<String>>(8)?,
            }))
        },
    );
    let items = list_items(&conn, id);
    match run {
        Ok(r) => Json(json!({"run": r, "items": items})),
        Err(e) => Json(json!({"error": e.to_string()})),
    }
}

fn list_items(conn: &rusqlite::Connection, run_id: i64) -> Vec<Value> {
    let mut stmt = match conn.prepare(
        "SELECT id, item_type, source_path, dest_path, status, \
         bytes_transferred, duration_ms, error_message \
         FROM provision_items WHERE run_id = ?1 ORDER BY id",
    ) {
        Ok(s) => s,
        Err(_) => return vec![],
    };
    stmt.query_map([run_id], |r| {
        Ok(json!({
            "id": r.get::<_, i64>(0)?,
            "item_type": r.get::<_, String>(1)?,
            "source": r.get::<_, String>(2)?,
            "dest": r.get::<_, String>(3)?,
            "status": r.get::<_, String>(4)?,
            "bytes": r.get::<_, u64>(5)?,
            "duration_ms": r.get::<_, u64>(6)?,
            "error": r.get::<_, Option<String>>(7)?,
        }))
    })
    .map(|rows| rows.flatten().collect())
    .unwrap_or_default()
}

//! Tests for convergio-provisioning.

mod ext_tests {
    use convergio_types::extension::Extension;
    use convergio_types::manifest::ModuleKind;

    use crate::ext::ProvisioningExtension;

    #[test]
    fn manifest_is_extension() {
        let pool = convergio_db::pool::create_memory_pool().unwrap();
        let ext = ProvisioningExtension::new(pool);
        let m = ext.manifest();
        assert_eq!(m.id, "convergio-provisioning");
        assert!(matches!(m.kind, ModuleKind::Extension));
        assert!(m.provides.iter().any(|c| c.name == "node-provisioning"));
    }

    #[test]
    fn has_one_migration() {
        let pool = convergio_db::pool::create_memory_pool().unwrap();
        let ext = ProvisioningExtension::new(pool);
        let migs = ext.migrations();
        assert_eq!(migs.len(), 1);
    }

    #[test]
    fn migrations_sql_valid() {
        let pool = convergio_db::pool::create_memory_pool().unwrap();
        let conn = pool.get().unwrap();
        let ext = ProvisioningExtension::new(pool.clone());
        for mig in ext.migrations() {
            conn.execute_batch(mig.up).unwrap();
        }
        let count: i64 = conn
            .query_row("SELECT COUNT(*) FROM provision_runs", [], |r| r.get(0))
            .unwrap();
        assert_eq!(count, 0);
        let count: i64 = conn
            .query_row("SELECT COUNT(*) FROM provision_items", [], |r| r.get(0))
            .unwrap();
        assert_eq!(count, 0);
    }

    #[test]
    fn health_ok() {
        let pool = convergio_db::pool::create_memory_pool().unwrap();
        let ext = ProvisioningExtension::new(pool);
        assert!(matches!(
            ext.health(),
            convergio_types::extension::Health::Ok
        ));
    }
}

mod types_tests {
    use crate::types::*;

    #[test]
